import { CLIENT_ID } from '../Config/Config';
import React, { useState, useEffect } from "react";
import { PayPalScriptProvider, PayPalButtons } from "@paypal/react-paypal-js";
import axios from 'axios';
import { useNavigate } from 'react-router-dom';
import Nav from './Nev';

const Checkout = () => {
    const [show, setShow] = useState(false);
    const [success, setSuccess] = useState(false);
    const [paymentMethod, setPaymentMethod] = useState(''); // 'paypal' | 'upi'
    const [upiId, setUpiId] = useState('');
    const [upiError, setUpiError] = useState('');
    const [upiSuccess, setUpiSuccess] = useState(false);
    const [orderID, setOrderID] = useState(false);
    const [processing, setProcessing] = useState(false);

    var localdata = localStorage.getItem("item", 0);
    var deleteid = localStorage.getItem("id", 0);
    const navigate = useNavigate();

    useEffect(() => {
        if (!localStorage.getItem("islogin")) {
            navigate('/login');
        }
    }, []);

    const fetchExchangeRate = async () => {
        try {
            const response = await axios.get('https://api.exchangerate-api.com/v4/latest/USD');
            return response.data.rates.INR;
        } catch (error) {
            return 83; // fallback rate
        }
    };

    function clearCart(uid) {
        fetch('http://localhost/Petshop/deletecart.php?uid=' + uid)
            .then((res) => res.json())
            .then((data) => console.log('Cart cleared:', data))
            .catch((error) => console.error('Error clearing cart:', error));
    }

    function saveOrder(orderId) {
        const postData = {
            pid: localStorage.getItem("pid"),
            order_id: orderId,
            uid: localStorage.getItem("id", 0),
            totalitem: localStorage.getItem("totalitem", 0),
            amount: localdata
        };
        axios({
            method: "POST",
            url: "http://localhost/Petshop/order.php",
            data: postData,
            headers: { "Content-Type": "multipart/form-data" },
        }).then(() => {
            console.log("Order saved");
        });
    }

    // PayPal
    const createOrder = async (data, actions) => {
        const exchangeRate = await fetchExchangeRate();
        const amountUSD = parseFloat(localdata) / exchangeRate;
        return actions.order.create({
            purchase_units: [{
                description: "PetShop",
                amount: {
                    currency_code: "USD",
                    value: amountUSD.toFixed(2),
                },
            }],
        }).then((orderId) => {
            setOrderID(orderId);
            localStorage.setItem("oid", orderId);
            saveOrder(orderId);
            return orderId;
        });
    };

    const onApprove = (data, actions) => {
        return actions.order.capture().then(function (details) {
            setSuccess(true);
        });
    };

    const onError = () => {
        alert("Payment mein problem aayi. Dobara try karein.");
    };

    useEffect(() => {
        if (success) {
            clearCart(deleteid);
            navigate('/myorder');
        }
    }, [success]);

    // UPI Payment
    const handleUpiPayment = () => {
        if (!upiId || !upiId.includes('@')) {
            setUpiError('Sahi UPI ID daalo (jaise: name@upi, number@paytm)');
            return;
        }
        setUpiError('');
        setProcessing(true);

        // Simulate UPI payment processing (2 seconds)
        setTimeout(() => {
            setProcessing(false);
            setUpiSuccess(true);
            const orderId = 'UPI' + Date.now();
            localStorage.setItem("oid", orderId);
            saveOrder(orderId);
            clearCart(deleteid);
        }, 2000);
    };

    const styles = {
        page: {
            minHeight: '100vh',
            backgroundColor: '#f0f4f8',
            fontFamily: "'Segoe UI', sans-serif",
        },
        container: {
            maxWidth: '620px',
            margin: '30px auto',
            padding: '0 16px 60px',
        },
        title: {
            fontSize: '26px',
            fontWeight: '700',
            color: '#1a202c',
            textAlign: 'center',
            marginBottom: '8px',
        },
        subtitle: {
            textAlign: 'center',
            color: '#718096',
            marginBottom: '28px',
            fontSize: '14px',
        },
        amountCard: {
            backgroundColor: 'white',
            borderRadius: '16px',
            padding: '20px 24px',
            marginBottom: '20px',
            boxShadow: '0 4px 20px rgba(0,0,0,0.07)',
            display: 'flex',
            justifyContent: 'space-between',
            alignItems: 'center',
        },
        amountLabel: {
            color: '#718096',
            fontSize: '14px',
            marginBottom: '4px',
        },
        amountValue: {
            fontSize: '28px',
            fontWeight: '800',
            color: '#38a169',
        },
        methodCard: {
            backgroundColor: 'white',
            borderRadius: '16px',
            padding: '24px',
            marginBottom: '20px',
            boxShadow: '0 4px 20px rgba(0,0,0,0.07)',
        },
        methodTitle: {
            fontSize: '16px',
            fontWeight: '700',
            color: '#2d3748',
            marginBottom: '16px',
        },
        methodOptions: {
            display: 'grid',
            gridTemplateColumns: '1fr 1fr',
            gap: '12px',
            marginBottom: '20px',
        },
        methodBtn: (selected) => ({
            padding: '16px',
            borderRadius: '12px',
            border: selected ? '2px solid #38a169' : '2px solid #e2e8f0',
            backgroundColor: selected ? '#f0fff4' : 'white',
            cursor: 'pointer',
            textAlign: 'center',
            transition: 'all 0.2s',
            fontWeight: '600',
            color: selected ? '#276749' : '#4a5568',
        }),
        methodIcon: {
            fontSize: '28px',
            marginBottom: '6px',
            display: 'block',
        },
        methodLabel: {
            fontSize: '14px',
        },
        upiBox: {
            marginTop: '16px',
        },
        upiLabel: {
            fontWeight: '600',
            color: '#4a5568',
            marginBottom: '8px',
            fontSize: '14px',
        },
        upiInput: {
            width: '100%',
            padding: '12px 16px',
            borderRadius: '10px',
            border: '2px solid #e2e8f0',
            fontSize: '15px',
            outline: 'none',
            boxSizing: 'border-box',
            marginBottom: '8px',
        },
        upiExamples: {
            fontSize: '12px',
            color: '#a0aec0',
            marginBottom: '16px',
        },
        upiPayBtn: {
            width: '100%',
            padding: '14px',
            backgroundColor: '#6c3dd1',
            color: 'white',
            border: 'none',
            borderRadius: '10px',
            fontWeight: '700',
            fontSize: '16px',
            cursor: 'pointer',
        },
        upiApps: {
            display: 'flex',
            gap: '10px',
            marginBottom: '16px',
            flexWrap: 'wrap',
        },
        upiAppPill: {
            padding: '6px 14px',
            backgroundColor: '#f7fafc',
            border: '1px solid #e2e8f0',
            borderRadius: '20px',
            fontSize: '13px',
            color: '#4a5568',
            fontWeight: '500',
        },
        error: {
            color: '#e53e3e',
            fontSize: '13px',
            marginBottom: '10px',
        },
        successBox: {
            textAlign: 'center',
            padding: '40px 20px',
        },
        successIcon: {
            fontSize: '72px',
            marginBottom: '16px',
        },
        successTitle: {
            fontSize: '24px',
            fontWeight: '700',
            color: '#276749',
            marginBottom: '8px',
        },
        successSub: {
            color: '#718096',
            marginBottom: '24px',
        },
        goOrderBtn: {
            padding: '14px 32px',
            backgroundColor: '#38a169',
            color: 'white',
            border: 'none',
            borderRadius: '10px',
            fontWeight: '700',
            fontSize: '16px',
            cursor: 'pointer',
        },
        processingBox: {
            textAlign: 'center',
            padding: '30px',
        },
        spinner: {
            fontSize: '40px',
            animation: 'spin 1s linear infinite',
        },
        homeBtn: {
            display: 'block',
            textAlign: 'center',
            marginTop: '12px',
            color: '#718096',
            cursor: 'pointer',
            fontSize: '14px',
            background: 'none',
            border: 'none',
            textDecoration: 'underline',
        }
    };

    if (upiSuccess) {
        return (
            <div style={styles.page}>
                <Nav />
                <div style={styles.container}>
                    <div style={{ ...styles.methodCard, ...styles.successBox }}>
                        <div style={styles.successIcon}>✅</div>
                        <h2 style={styles.successTitle}>Payment Successful!</h2>
                        <p style={styles.successSub}>
                            UPI se ₹{parseInt(localdata).toLocaleString()} ka payment ho gaya!<br />
                            Aapka order place ho gaya hai.
                        </p>
                        <button style={styles.goOrderBtn} onClick={() => navigate('/myorder')}>
                            My Orders Dekhein →
                        </button>
                        <br />
                        <button style={styles.homeBtn} onClick={() => navigate('/')}>
                            Home pe jaayein
                        </button>
                    </div>
                </div>
            </div>
        );
    }

    return (
        <div style={styles.page}>
            <Nav />
            <div style={styles.container}>
                <h1 style={styles.title}>💳 Checkout</h1>
                <p style={styles.subtitle}>Payment method chunein aur order complete karein</p>

                {/* Amount Summary */}
                <div style={styles.amountCard}>
                    <div>
                        <div style={styles.amountLabel}>Total Amount</div>
                        <div style={styles.amountValue}>₹{parseInt(localdata).toLocaleString()}</div>
                    </div>
                    <div style={{ fontSize: '40px' }}>🛍️</div>
                </div>

                {/* Payment Method Selection */}
                <div style={styles.methodCard}>
                    <div style={styles.methodTitle}>Payment Method chunein</div>

                    <div style={styles.methodOptions}>
                        <button
                            style={styles.methodBtn(paymentMethod === 'upi')}
                            onClick={() => { setPaymentMethod('upi'); setShow(false); }}
                        >
                            <span style={styles.methodIcon}>📱</span>
                            <span style={styles.methodLabel}>UPI Payment</span>
                        </button>
                        <button
                            style={styles.methodBtn(paymentMethod === 'paypal')}
                            onClick={() => { setPaymentMethod('paypal'); setShow(true); }}
                        >
                            <span style={styles.methodIcon}>🅿️</span>
                            <span style={styles.methodLabel}>PayPal</span>
                        </button>
                    </div>

                    {/* UPI Section */}
                    {paymentMethod === 'upi' && (
                        <div style={styles.upiBox}>
                            <div style={styles.upiLabel}>Supported UPI Apps:</div>
                            <div style={styles.upiApps}>
                                <span style={styles.upiAppPill}>📲 PhonePe</span>
                                <span style={styles.upiAppPill}>💚 GPay</span>
                                <span style={styles.upiAppPill}>🟦 Paytm</span>
                                <span style={styles.upiAppPill}>🔵 BHIM</span>
                                <span style={styles.upiAppPill}>🟠 Amazon Pay</span>
                            </div>

                            <div style={styles.upiLabel}>Apna UPI ID daalo:</div>
                            <input
                                style={styles.upiInput}
                                type="text"
                                placeholder="example@paytm / 9876543210@ybl"
                                value={upiId}
                                onChange={(e) => setUpiId(e.target.value)}
                            />
                            <div style={styles.upiExamples}>
                                Examples: name@paytm | mobileno@ybl | name@okaxis
                            </div>

                            {upiError && <div style={styles.error}>⚠️ {upiError}</div>}

                            {processing ? (
                                <div style={styles.processingBox}>
                                    <div>⏳ Payment process ho raha hai...</div>
                                </div>
                            ) : (
                                <button style={styles.upiPayBtn} onClick={handleUpiPayment}>
                                    📱 UPI se ₹{parseInt(localdata).toLocaleString()} Pay Karein
                                </button>
                            )}
                        </div>
                    )}

                    {/* PayPal Section */}
                    {paymentMethod === 'paypal' && (
                        <PayPalScriptProvider options={{ "client-id": CLIENT_ID }}>
                            <PayPalButtons
                                style={{ layout: "vertical", shape: "rect" }}
                                createOrder={createOrder}
                                onApprove={onApprove}
                                onError={onError}
                            />
                        </PayPalScriptProvider>
                    )}

                    {/* No method selected */}
                    {!paymentMethod && (
                        <div style={{ textAlign: 'center', color: '#a0aec0', padding: '20px', fontSize: '14px' }}>
                            ☝️ Upar se payment method chunein
                        </div>
                    )}
                </div>

                <button style={styles.homeBtn} onClick={() => navigate('/cart')}>
                    ← Cart pe wapas jaayein
                </button>
            </div>
        </div>
    );
};

export default Checkout;
